import React, { useState, useEffect, useRef } from 'react';
import { FaPhone, FaMapMarkerAlt, FaBars, FaTimes, FaChevronDown, FaClock } from 'react-icons/fa';
import { FiHome, FiGrid, FiLogIn, FiLayers, FiTool, FiShield } from 'react-icons/fi';
import { Helmet } from 'react-helmet';
import './header.css';

const Header: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [isServicesOpen, setIsServicesOpen] = useState(false);
  const topBarHeightRef = useRef(0);
  const rafRef = useRef<number | null>(null);
  const servicesTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    // Calculate top bar height for scroll calculations
    const topBar = document.querySelector('.top-bar');
    if (topBar) {
      const height = topBar.clientHeight;
      topBarHeightRef.current = height;
      document.documentElement.style.setProperty('--top-bar-height', `${height}px`);
    }

    const handleScroll = () => {
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
      }

      rafRef.current = requestAnimationFrame(() => {
        const scrolled = window.scrollY > topBarHeightRef.current;
        setIsScrolled(scrolled);
      });
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    // Initial check
    handleScroll();

    return () => {
      window.removeEventListener('scroll', handleScroll);
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
      }
    };
  }, []);

  useEffect(() => {
    if (isMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isMenuOpen]);

  // ... (navLinks and servicesItems remain the same)
  const servicesItems = [
    { title: 'Siding', description: 'Professional siding installation and repair', icon: <FiHome />, href: '/siding' },
    { title: 'Windows', description: 'Quality window installation and replacement', icon: <FiGrid />, href: '/windows' },
    { title: 'Doors', description: 'Expert door installation and replacement', icon: <FiLogIn />, href: '/doors' },
    { title: 'Decks', description: 'Custom deck design and construction', icon: <FiLayers />, href: '/decks' },
    { title: 'Rot Repair', description: 'Comprehensive rot repair services', icon: <FiTool />, href: '/rot-repair' },
    { title: 'Roofing Repair', description: 'Reliable Roofing installation and repair', icon: <FiShield />, href: '/roofing' }
  ];

  const navLinks = [
    { label: 'Home', href: '/' },
    { label: 'Services', href: '/#services', hasDropdown: true },
    { label: 'About', href: '/#about' },
    { label: 'Gallery', href: '/#gallery' },
    { label: 'Testimonials', href: '/#testimonials' },
  ];

  const handleServicesMouseEnter = () => {
    if (servicesTimeoutRef.current) clearTimeout(servicesTimeoutRef.current);
    setIsServicesOpen(true);
  };

  const handleServicesMouseLeave = () => {
    servicesTimeoutRef.current = setTimeout(() => setIsServicesOpen(false), 150);
  };

  return (
    <header className={`header-main ${isScrolled ? 'is-stuck' : ''}`}>
      <Helmet>
        <link rel="icon" type="image/png" href="https://ik.imagekit.io/dloitl7fd8/ChatGPT_Image_Jan_24__2026__03_41_08_AM-removebg-preview.png" />
      </Helmet>
      {/* Top Bar */}
      <div className="top-bar">
        <div className="container">
          <div className="top-bar-content">
            <div className="top-bar-left">
              <a href="tel:+12073413102" className="top-bar-item" aria-label="Call us">
                <FaPhone className="top-bar-icon" />
                <span className="top-bar-text">Call Now: (207) 341-3102</span>
              </a>
              <div className="top-bar-item">
                <FaClock className="top-bar-icon" />
                <span className="top-bar-text">Mon-Fri: 7AM-6PM | Sat: 8AM-4PM</span>
              </div>
            </div>
            <div className="top-bar-right">
              <div className="top-bar-item">
                <FaMapMarkerAlt className="top-bar-icon" />
                <span className="top-bar-text">219 Etna Rd, Plymouth, ME 04969</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Navbar */}
      <nav className={`navbar ${isScrolled ? 'navbar-scrolled' : ''}`}>
        <div className="container">
          <a href="/" className="logo">
            <img src="https://ik.imagekit.io/dloitl7fd8/ChatGPT_Image_Jan_24__2026__03_41_08_AM-removebg-preview.png" alt="Logo" />
          </a>

          <div className="nav-desktop">
            <ul className="nav-links">
              {navLinks.map((link) => (
                <li
                  key={link.label}
                  className={link.hasDropdown ? 'nav-item-dropdown' : ''}
                  onMouseEnter={link.hasDropdown ? handleServicesMouseEnter : undefined}
                  onMouseLeave={link.hasDropdown ? handleServicesMouseLeave : undefined}
                >
                  <a href={link.href} className="nav-link">
                    {link.label}
                    {link.hasDropdown && <FaChevronDown className={`dropdown-arrow ${isServicesOpen ? 'dropdown-arrow-open' : ''}`} />}
                  </a>
                  {link.hasDropdown && (
                    <div className={`services-dropdown ${isServicesOpen ? 'services-dropdown-open' : ''}`}>
                      <div className="services-dropdown-content">
                        <div className="services-grid">
                          {servicesItems.map((s, i) => (
                            <a key={i} href={s.href} className="service-item" onClick={() => setIsServicesOpen(false)}>
                              <div className="service-icon">{s.icon}</div>
                              <div className="service-content">
                                <h4 className="service-title">{s.title}</h4>
                                <p className="service-description">{s.description}</p>
                              </div>
                            </a>
                          ))}
                        </div>
                      </div>
                    </div>
                  )}
                </li>
              ))}
            </ul>
            <a href="/contact" className="cta-button-head">Get Free Quote</a>
          </div>

          <button className="mobile-menu-button" onClick={() => setIsMenuOpen(!isMenuOpen)}>
            {isMenuOpen ? <FaTimes /> : <FaBars />}
          </button>
        </div>

        <div className={`mobile-menu-overlay ${isMenuOpen ? 'mobile-menu-open' : ''}`}>
          <div className="mobile-menu-content">
            <ul className="mobile-nav-links">
              {navLinks.map((link) => (
                <li key={link.label}>
                  {link.hasDropdown ? (
                    <div className="mobile-dropdown">
                      <button className="mobile-nav-link mobile-dropdown-toggle" onClick={() => setIsServicesOpen(!isServicesOpen)}>
                        {link.label}
                        <FaChevronDown className={`mobile-dropdown-arrow ${isServicesOpen ? 'mobile-dropdown-arrow-open' : ''}`} />
                      </button>
                      <div className={`mobile-services-dropdown ${isServicesOpen ? 'mobile-services-dropdown-open' : ''}`}>
                        {servicesItems.map((s, i) => (
                          <a key={i} href={s.href} className="mobile-service-item" onClick={() => { setIsMenuOpen(false); setIsServicesOpen(false); }}>
                            <div className="mobile-service-icon">{s.icon}</div>
                            <span>{s.title}</span>
                          </a>
                        ))}
                      </div>
                    </div>
                  ) : (
                    <a href={link.href} className="mobile-nav-link" onClick={() => setIsMenuOpen(false)}>{link.label}</a>
                  )}
                </li>
              ))}
            </ul>
            <div className="mobile-menu-bottom">
              <a href="/contact" className="mobile-cta-button" onClick={() => setIsMenuOpen(false)}>Get Free Quote</a>
              <div className="mobile-contact-info">
                <div className="mobile-contact-item"><FaPhone /> <span>(207) 341-3102</span></div>
                <div className="mobile-contact-item"><FaMapMarkerAlt /> <span>219 Etna Rd, Plymouth, ME 04969</span></div>
              </div>
            </div>
          </div>
        </div>
      </nav>
    </header>
  );
};

export default Header;